// 外设
#include <dev/console.h>
#include <dev/plic.h>
#include <dev/timer.h>
#include <dev/disk.h>

// IO
#include <lib/printf.h> 
#include <lib/log.h>

// 内存管理
#include <mm/kmalloc.h>
#include <mm/pmm.h>
#include <mm/vmm.h>

// CPU状态和进程线程管理
#include <proc/cpu.h>
#include <proc/proc.h>
#include <proc/sched.h>
#include <proc/thread.h>
#include <proc/tsleep.h>

// 共享内存
#include <ipc/shm.h>

// 信号
#include <signal/itimer.h>
#include <signal/signal.h>

// 异常中断
#include <trap/trap.h>

// FS
#include <fs/buf.h>
#include <fs/fat32.h>
#include <fs/fd.h>
#include <fs/vfs.h>
#include <futex/futex.h>


// 宏定义
#ifdef SIFIVE
#define IGNORE_HART0 1
#else
#define IGNORE_HART0 0
#endif

// 变量定义
volatile static int hart_started[NCPU];
volatile static int hart_first = 1;
volatile static int kern_inited = 0;

static __inline__ __attribute__((always_inline)) void StarsOSLogo();
static __inline__ __attribute__((always_inline)) void hart_set_clear();
static __inline__ __attribute__((always_inline)) void hart_set_started();
static __inline__ __attribute__((always_inline)) void hart_start_all();
static __inline__ __attribute__((always_inline)) void hart_wait_all();

void kernel_start(u64_t hartid)
{
    // hart进入初始态
    // 不开启页表（完全用物理地址空间）
    // 不开启中断（从而需要快速进入下一状态）

    w_satp(0);
    w_sie(r_sie() | SIE_SEIE | SIE_STIE);

	// 在每个CPU的tp寄存器中保存hartid
	w_tp(hartid);
	w_stvec((u64_t)inittrap);

    cons_init();
    printInit();

    printf("sstatus = 0x%x\n", r_sstatus());
    printf("sie = 0x%x\n", r_sie());

    if(hart_first == 1) /* 是启动核 */
    {
        hart_first = 0;
        mem_barrier();

        StarsOSLogo();
        printf("StarsOS kernel is booting (on hart %d) total: %d\n", cpu_this_id(), NCPU);
        pmmInit();
        vmmInit(); /* 内核态地址空间初始化 */
        vmEnable(); /* 开启分页 */

        // 正式进入内核态
        printf("StarsOS kernel is entering kernel state (on hart %d)\n", cpu_this_id());
        trapInitHart();
        timerInit();
        plicInitHart();
        thread_init();
		proc_init();
		sig_init();
		futexevent_init();
		tsleep_init();
        disk_init();
		plicInit();

		fd_init();
		kmalloc_init();
        shm_init();
		socket_init();
		itimer_init();
        printf("StarsOS kernel boot end, start all harts.\n");

        PROC_CREATE(user, "user");
        hart_set_clear();
		hart_set_started();
		hart_start_all();

        mem_barrier();

        kern_inited = 1;
        hart_wait_all();

        mem_barrier();

    }
    else /* 其他核心 */
    {
        printf("11!\n");
        while(!kern_inited)
        {
            mem_barrier();
        }
        vmEnable(); /* 开启分页 */

        // 正式进入内核态
        printf("StarsOS kernel is entering kernel state (on hart %d)\n", cpu_this_id());
        trapInitHart();
        timerInit();
        plicInitHart();


        hart_set_started();
        hart_wait_all();
    }

    sched_init();
    printf("不能到这里哦！\n");
    while(1);
}

static __inline__ __attribute__((always_inline)) void StarsOSLogo()
{
    printf("\n");
    printf("  ____  _                  ___  ____  \n");
    printf(" / ___|| |_ __ _ _ __ ___ / _ \\/ ___| \n");
    printf(" \\___ \\| __/ _` | '__/ __| | | \\___ \\ \n");
    printf("  ___) | || (_| | |  \\__ \\ |_| |___) |\n");
    printf(" |____/ \\__\\__,_|_|  |___/\\___/|____/ \n");
	printf("\n");
}

static __inline__ __attribute__((always_inline)) void hart_set_clear()
{
    mem_barrier();
    for(int i = 0; i < NCPU; i++) 
    {
		hart_started[i] = 0;
	}
    mem_barrier();
}

static __inline__ __attribute__((always_inline)) void hart_set_started()
{
    mem_barrier();
    hart_started[cpu_this_id()] = 1;
    mem_barrier();
}

static __inline__ __attribute__((always_inline)) void hart_start_all()
{
    for(int i = 0; i < NCPU; i++) 
    {
		if(!hart_started[i]) 
        {
			struct sbiret ret = SBI_HART_START(i, 0x80200000, 0);
			if(ret.error) 
            {
				printf("Hart %d start hart %d error: %d\n", cpu_this_id(), i, ret.error);
				hart_started[i] = 2; // 跳过启动失败的核
				__sync_synchronize();
			} 
            else 
            {
				printf("Hart %d start hart %d success\n", cpu_this_id(), i);
			}

			// unsigned long mask = (1 << i);
			// SBI_SEND_IPI(&mask, 0);
		}
	}
    // for(int i = 0; i < NCPU; i++) 
    // {
    //     if(i == cpu_this_id()) /* 跳过启动核 */
    //     {
    //         break;
    //     }
	// 	if(!hart_started[i]) 
    //     {
	// 		struct sbiret ret = SBI_HART_START(i, 0x80200000, 0);
	// 	}
	// }
}

static __inline__ __attribute__((always_inline)) void hart_wait_all()
{
    u64_t cnt = 0;
    printf("Hart %d is waiting\n", cpu_this_id());
    while(1)
    {
        mem_barrier();
        int all_started = 1;

        if(++cnt == (100000000 * cpu_this_id())) 
        {
			printf("\n");
			for(int i = IGNORE_HART0 ? 1 : 0; i < NCPU; i++) 
            {
				// struct sbiret ret = SBI_HART_GET_STATUS(i);
				// if (ret.error) {
				// 	printf("Hart %d get hart %d status error: %d\n", cpu_this_id(), i, ret.error);
				// } else {
				// 	printf("Hart %d get hart %d status: %d\n", cpu_this_id(), i, ret.value);
				// }
			}
			printf("\n");
			cnt = 0;
		}

        for(int i = 0; i < NCPU; i++)
        {
            if(!hart_started[i])
            {
                all_started = 0;
                break;
            }
        }
        if(all_started)
        {
            break;
        }
    }

}

#include <mm/pmm.h> 		/* 源文件 */
#include <mm/memlayout.h> 	/* 初始态物理内存布局 */
#include <arch/arch.h>		/* 类型 */

// IO
#include <lib/error.h>
#include <lib/log.h>
#include <lib/printf.h>

#include <fs/buf.h>

#include <lib/string.h>
#include <proc/proc.h>
#include <proc/thread.h>
#include <fs/dirent.h>
#include <signal/signal.h>



u64_t pageleft = 0;
u64_t npage = 0;
Page pages[(MEMORY << 20) / PAGE_SIZE] = {0};
PageList pageFreeList;



// 模块初始化函数

static void *pmInitPush(u64_t start, u64_t size, u64_t *freemem) {
	u64_t push = PGROUNDUP(size);
	*freemem = start + push;
	log(MM_GLOBAL, "\tPhysical Memory Used: 0x%08lx~0x%08lx\n", start, *freemem);
	return memset((void *)start, 0, push);
}

void pmmInit() 
{
	extern char end[]; /* 来自kernel.ld */
	log(MM_GLOBAL, "Physical Memory Init Start: End = 0x%0lx\n", end);
	u64_t freemem = PGROUNDUP((u64_t)end);
	npage = (MEMORY << 20) / PAGE_SIZE;

	extern Dirent *dirents;
	dirents = pmInitPush(freemem, MAX_DIRENT * sizeof(Dirent), &freemem);


	// 第二部分：初始化空闲链表
	log(MM_GLOBAL, "Physical Memory Freelist Init Start: Freemem = 0x%0lx\n", freemem);
	LIST_INIT(&pageFreeList);
	u64_t pageused = (freemem - MEMBASE) >> PAGE_SHIFT; // 已经使用的内存页数
	for (u64_t i = 0; i < pageused; i++) {
		pages[i].ref = 1;
	}
	log(MM_GLOBAL, "\tTo pages[0:%d) used\n", pageused);
	for (u64_t i = pageused; i < npage; i++) {
		LIST_INSERT_HEAD(&pageFreeList, &pages[i], link);
	}
	pageleft = npage - pageused;
	log(MM_GLOBAL, "\tFrom pages[%d:%d) free\n", pageused, npage);

	log(MM_GLOBAL, "Physical Memory Init Finished, `pm` Functions Available!\n");
}

// 纯接口函数

inline u64_t __attribute__((warn_unused_result)) pageToPpn(Page *p) {
	return p - pages;
}

inline u64_t __attribute__((warn_unused_result)) pageToPa(Page *p) {
	return MEMBASE + (pageToPpn(p) << PAGE_SHIFT);
}

inline Page *__attribute__((warn_unused_result)) paToPage(u64_t pa) {
	return &pages[(pa - MEMBASE) >> PAGE_SHIFT];
}

inline u64_t __attribute__((warn_unused_result)) pmTop() {
	return MEMBASE + (npage << PAGE_SHIFT);
}

// 功能接口函数

Page *__attribute__((warn_unused_result)) pmAlloc() {
	Page *pp = LIST_FIRST(&pageFreeList);
	if (pp == NULL) {
		pp = pages;
		panic("pmAlloc: no free page");
	}
	// 从空闲页链表中移除该页
	LIST_REMOVE(pp, link);
	pageleft--;
	// 清空页面内容并返回
	memset((void *)pageToPa(pp), 0, PAGE_SIZE);
	log(MM_MODULE, "\tAlloc pm-page: %d(%d)\n", pageToPpn(pp), pageleft);
	return pp;
}

void pmPageIncRef(Page *pp) {
	panic_on(pp == NULL);
	pp->ref++;
}

void pmPageDecRef(Page *pp) {
	panic_on(pp == NULL || pp->ref == 0);
	pp->ref--;
	if (pp->ref == 0) {
		LIST_INSERT_HEAD(&pageFreeList, pp, link);
		pageleft++;
		log(MM_MODULE, "\tFree pm-page: %d(%d)\n", pageToPpn(pp), pageleft);
	}
}

#include <mm/vmm.h> 	/* 源文件 */
#include <lock/mutex.h> /* 锁 */

// 输出
#include <lib/error.h>
#include <lib/log.h>
#include <lib/string.h>
#include <mm/pmm.h>


Pte *kernPd;
mutex_t kvmlock;

// 纯接口函数

static inline Pte pageToPte(Page *p);
static inline Page *pteToPage(Pte pte);
static inline void pp_dec_on_valid(pte_t pte);
static inline void pp_inc_on_valid(pte_t pte);
static inline void flush_tlb_if_need(pte_t *pd, u64 va);
static void ptModify(Pte *pte, Pte value);
static void ptClear(Pte *pte);
static Pte *ptWalk(Pte *pageDir, u64 va, bool create);
static void vmInitMap(u64 pa, u64 va, u64 len, u64 perm);
static void memoryTest();



void vmmInit() 
{
	// 第零步：初始化模块锁
	mtx_init(&kvmlock, "kvmlock", false, MTX_SPIN | MTX_RECURSE);

	// 第一步：初始化内核页目录
	log(LEVEL_GLOBAL, "Virtual Memory Init Start\n");
	kernPd = (Pte *)pageToPa(pmAlloc());

	// 第二步：映射UART寄存器，用于串口输入输出
	vmInitMap(UART0, UART0, PAGE_SIZE, PTE_R | PTE_W);
	log(LEVEL_GLOBAL, "UART map ok!\n");

	// SD卡
	// vmInitMap(SPI_CTRL_ADDR, SPI_CTRL_ADDR, PAGE_SIZE, PTE_R | PTE_W);

	// 第三步：映射MMIO的硬盘寄存器，可读可写
	vmInitMap(VIRTIO0, VIRTIO0, PAGE_SIZE, PTE_R | PTE_W);

	// vmInitMap(RTC_BASE, RTC_BASE, PAGE_SIZE, PTE_R | PTE_W);

	// 第四步：PLIC寄存器
	vmInitMap(PLIC, PLIC, 0x400000, PTE_R | PTE_W); // todo:literal

	// 第五步：内核代码段
	extern char end_text[];
	vmInitMap(KERNBASE, KERNBASE, (u64)end_text - KERNBASE, PTE_R | PTE_X);

	// 第六步：内核数据段(就是代码段的结束位置到物理内存的最高位置)
	vmInitMap((u64)end_text, (u64)end_text, pmTop() - (u64)end_text, PTE_R | PTE_W);

	// 第七步：Trampoline段的映射
	extern char trampoline[];
	vmInitMap(PGROUNDDOWN((u64)trampoline), TRAMPOLINE, PAGE_SIZE, PTE_R | PTE_X);

	// 第八步：测试
	memoryTest();
	log(LEVEL_GLOBAL, "Virtual Memory Init Finished, `vm` Functions Available!\n");
}

// 功能接口函数

/**
 * @brief 在内核中申请一个物理页，返回其物理地址
 */
u64 kvmAlloc() {
	mtx_lock(&kvmlock);
	Page *pp = pmAlloc();
	pmPageIncRef(pp);
	mtx_unlock(&kvmlock);
	return pageToPa(pp);
}

void kvmFree(u64 pa) {
	mtx_lock(&kvmlock);
	Page *pp = paToPage(pa);
	pmPageDecRef(pp);
	mtx_unlock(&kvmlock);
}

u64 vmAlloc() {
	mtx_lock(&kvmlock);
	Page *pp = pmAlloc();
	mtx_unlock(&kvmlock);
	return pageToPa(pp);
}

Pte ptLookup(Pte *pgdir, u64 va) {
	mtx_lock(&kvmlock);
	Pte *pte = ptWalk(pgdir, va, false);
	mtx_unlock(&kvmlock);
	return pte == NULL ? 0 : *pte;
}

/**
 * @brief 修改已有映射、或添加映射
 */
err_t ptMap(Pte *pgdir, u64 va, u64 pa, u64 perm) {
	mtx_lock(&kvmlock);
	// 遍历页表尝试获得 va 对应的页表项地址
	Pte *pte = ptWalk(pgdir, va, false);
	// 若不存在对应的页表项，则进行创建
	if (pte == NULL) {
		pte = ptWalk(pgdir, va, true);
	}

	/**
	 * 对于页表项的 3 种状态间转换（有效、被动有效、无效）：
	 * 1. 有效 -> 有效：
	 * 		修改页表项内容（分支 1）
	 * 2. 有效 -> 被动有效：
	 * 		不应该存在这种情况
	 * 3. 有效 -> 无效：
	 * 		不应该存在这种情况，应该使用 ptUnmap
	 * 4. 被动有效 -> 有效：
	 * 		分配页面，修改页表项内容（分支 3）
	 * 5. 被动有效 -> 被动有效：
	 * 		修改页表项内容，更新权限（分支 2）
	 * 6. 被动有效 -> 无效：
	 * 		不应该存在这种情况，应该使用 ptUnmap
	 * 7. 无效 -> 有效：
	 * 		分配页面，修改页表项内容（分支 3）
	 * 8. 无效 -> 被动有效：
	 * 		修改页表项内容，更新权限（分支 2）
	 * 9. 无效 -> 无效：
	 * 		这是在干什么？
	 */
	if (*pte & PTE_V) {
		// 原页表项有效时，修改映射（此时不应该是添加被动映射）
		assert(pa != 0);
		ptModify(pte, paToPte(pa) | perm | PTE_V);

	} else if (pa == 0) {
		// 原页表项无效，添加被动映射（传入的物理地址必须为零）
		assert(perm & PTE_U);
		ptModify(pte, perm);
		mtx_unlock(&kvmlock);
		return 0; // 直接返回，不用刷新 TLB
	} else {
		// 原页表项无效，添加有效映射，外部已申请了页面
		assert(pa >= MEMBASE);
		ptModify(pte, paToPte(pa) | perm | PTE_V);
	}

	// 如果操作的是当前页表，刷新 TLB
	flush_tlb_if_need(pgdir, va);
	mtx_unlock(&kvmlock);
	return 0;
}

err_t ptUnmap(Pte *pgdir, u64 va) {
	mtx_lock(&kvmlock);
	Pte *pte = ptWalk(pgdir, va, false);
	if (*pte == 0) {
		return -E_NO_MAP;
	}
	// 维护引用计数并清除页表项内容
	ptClear(pte);

	flush_tlb_if_need(pgdir, va); // todo: optimize

	mtx_unlock(&kvmlock);
	return 0;
}

static inline Pte pageToPte(Page *p) 
{
	return paToPte(MEMBASE) + (pageToPpn(p) << PTE_PPNSHIFT);
}

static inline Page *pteToPage(Pte pte) 
{
	assert(pteToPa(pte) > MEMBASE);
	return paToPage(pteToPa(pte));
}

// 映射操作包裹（解引用映射时使用，若传入页表项指向实际内存页面则更新映射次数）
static inline void pp_dec_on_valid(pte_t pte) 
{
	if (pte & PTE_V && pteToPa(pte) >= MEMBASE) {
		pmPageDecRef(pteToPage(pte));
	}
}

static inline void pp_inc_on_valid(pte_t pte) 
{
	if (pte & PTE_V && pteToPa(pte) >= MEMBASE) {
		pmPageIncRef(pteToPage(pte));
	}
}

static inline void flush_tlb_if_need(pte_t *pd, u64 va) 
{
	// // 如果修改的是当前的TLB，就刷新TLB
	// if (ptFetch() == pd) {
	tlbFlush(va); // 无条件刷新 va 的 TLB 项
	// }
}

/**
 * @brief 修改传入的页表项指针指向的页表项至传入的新值，若指向物理页相同则仅修改权限
 * @note PTE_V 代表该页表项的物理页号有效，即存在对应物理页。因此对于修改前后会检查 PTE_V 标志并对物理页的映射次数进行维护。
 */
static void ptModify(Pte *pte, Pte value) 
{
	u64 oldpa = pteToPa(*pte);
	u64 newpa = pteToPa(value);
	if (oldpa == newpa) {
		// 页表项指向的物理页没有变化，仅修改权限
		*pte = value;
	} else {
		// 页表项指向的物理页发生了变化，需要修改映射
		pp_dec_on_valid(*pte);
		*pte = value;
		pp_inc_on_valid(value);
	}
}

/**
 * @brief 将传入的页表项指针指向的页表项清零，若指向物理页则取消映射
 */
static void ptClear(Pte *pte) 
{
	// 取消原先的映射
	pp_dec_on_valid(*pte);
	*pte = 0;
}

static Pte *ptWalk(Pte *pageDir, u64 va, bool create) 
{
	Pte *curPageTable = pageDir;

	// 从顶级页目录开始，依次获取每一级页表
	for (int i = 1; i < 3; i++) {
		// 获取当前页表项
		Pte *curPte = &curPageTable[PTX(va, i)];
		// 检查当前页表项是否存在
		if (*curPte & PTE_V) {
			// 如果存在，获取下一级页表
			curPageTable = (Pte *)pteToPa(*curPte);
		} else {
			// 如果不存在，创建下一级页表
			if (create) {
				log(LEVEL_MODULE, "\tcreate a page for level %d in va 0x%016lx\n",
				    i, va);
				Page *newPage = pmAlloc();
				// 将新页表的物理地址写入当前页表项
				ptModify(curPte, pageToPte(newPage) | PTE_V);
				flush_tlb_if_need(pageDir, va);
				// 将新页表的虚拟地址赋值给 curPageTable
				curPageTable = (Pte *)pageToPa(newPage);
			} else {
				return NULL;
			}
		}
	}
	// 返回最后一级页表项
	return &curPageTable[PTX(va, 3)];
}

// 初始化函数
static void vmInitMap(u64 pa, u64 va, u64 len, u64 perm) {
	for (u64 off = 0; off < len; off += PAGE_SIZE) {
		*(u64 *)ptWalk(kernPd, va + off, true) = (paToPte(pa + off) | perm | PTE_V);
	}
}

static void memoryTest() 
{
	u64 pte;
	for (uint64 va = KERNBASE; va < pmTop(); va += PAGE_SIZE) {
		pte = ptLookup(kernPd, va);
		assert(pteToPa(pte) == va);
	}
	log(LEVEL_GLOBAL, "Passed Kernel MemMap Test!\n");
}

Pte *ptFetch() {
	return ((Pte *)((r_satp() & ((1ul << 44) - 1)) << 12));
}

