void proc_init() 
{
	extern mutex_t pid_lock;
	mtx_init(&pid_lock, "pid_lock", false, MTX_SPIN);
	mtx_init(&proc_freelist.pl_lock, "proc_freelist", false, MTX_SPIN);
	LIST_INIT(&proc_freelist.pl_list);
	for(int i = NPROC - 1; i >= 0; i--) 
    {
		proc_t *p = &procs[i];
		LIST_INSERT_HEAD(&proc_freelist.pl_list, p, p_list);
		mtx_init(&p->p_lock, "proc", false, MTX_SPIN | MTX_RECURSE);
		TAILQ_INIT(&p->p_threads);
		LIST_INIT(&p->p_children);
		p->p_parent = NULL;
		p->p_pt = NULL;
		p->p_trapframe = NULL;
		p->p_brk = 0;
	}
}


/*
    功能：分配一个进程
*/
proc_t *proc_alloc() 
{
	plist_critical_enter(&proc_freelist);
	if(LIST_EMPTY(&proc_freelist.pl_list)) 
    {
		plist_critical_exit(&proc_freelist);
		error("no free proc");
	}

	proc_t *p = LIST_FIRST(&proc_freelist.pl_list);
	LIST_REMOVE(p, p_list);
	proc_lock(p);
	plist_critical_exit(&proc_freelist);

	// 初始化进程字段
	p->p_status = USED;
	p->p_pid = pid_alloc(p);
	memset(&p->p_startzero, 0, rangeof(proc_t, p_startzero, p_endzero));
	proc_initupt(p);
	return p;
}

void proc_addtd(proc_t *p, thread_t *td) 
{
	// 需要已获取二者的锁
	td->td_proc = p;
	TAILQ_INSERT_HEAD(&p->p_threads, td, td_plist);
}

/*
    功能：分配并初始化一个新的用户空间页表
*/
void proc_initupt(proc_t *p) 
{
	// 分配页表
	pte_t upt = kvmAlloc(); /* 页表 */
	p->p_pt = (pte_t *)upt;
	extern char trampoline[]; /* TRAMPOLINE */
	panic_on(ptMap(p->p_pt, TRAMPOLINE, (u64)trampoline, PTE_R | PTE_X | PTE_G));
	extern char user_sig_return[]; /* signal TRAMPOLINE */
	panic_on(ptMap(p->p_pt, SIGNAL_TRAMPOLINE, (u64)user_sig_return, PTE_R | PTE_X | PTE_U));
	p->p_trapframe = (trapframe_t *)vmAlloc(); /* trapframe */
	panic_on(ptMap(p->p_pt, TRAPFRAME, (u64)p->p_trapframe, PTE_R | PTE_W));
}

int proc_initucode_by_binary(proc_t *p, thread_t *inittd, const void *bin, size_t size, stack_arg_t *parg) 
{
	panic_on(loadCode(inittd, bin, size, &p->p_brk));
	if(parg) 
    {
		parseElf(inittd, bin, size, parg);
	}
	return 0;
}


/*
    功能：分配并初始化一个新的用户空间栈
*/
void proc_initustack(proc_t *p, thread_t *inittd) 
{
	for(int i = 0; i < TD_USTACK_INIT_PAGE_NUM; i++) /* 分配用户栈空间 */
    {
		u64 pa = vmAlloc();
		u64 va = TD_USTACK_INIT_BOTTOM + i * PAGE_SIZE;
		panic_on(ptMap(p->p_pt, va, pa, PTE_R | PTE_W | PTE_U));
	}
	for(int i = 0; i < TD_USTACK_EXTEND_PAGE_NUM; i++) /* 分配可拓展的用户栈空间 */
    {
		u64 va = TD_USTACK_BOTTOM + i * PAGE_SIZE;
		panic_on(ptMap(p->p_pt, va, 0, PTE_R | PTE_W | PTE_U));
	}
	inittd->td_trapframe.sp = USTACKTOP;
	p->p_brk = 0;
}

void proc_recycleupt(proc_t *p) 
{
	pdWalk(p->p_pt, vmUnmapper, kvmUnmapper, NULL); /* 解引用全部用户页表 */
	p->p_pt = 0;
	p->p_brk = 0;
}

/*
    功能：将给定的进程运行参数压入用户栈
    传参：
        td：线程指针
        argpt：存储exec的新进程栈上内容的临时页表指针
        argc：参数数量
        argv：用户空间内的参数指针
        envp：用户空间内的环境变量指针。为0表示没有环境变量
*/
stack_arg_t proc_setustack(thread_t *td, pte_t *argpt, u64_t argc, char **argv, u64_t envp, argv_callback_t callback) 
{
	pte_t *src_pt = td->td_proc->p_pt;
	char **argvbuf = kmalloc(MAXARG * sizeof(char *));

	// 1. 拷入argv数组
	u64 len_argv = push_uarg_array(src_pt, argpt, argv, &td->td_trapframe.sp, argvbuf, callback);

	// 2. 拷入envp数组
	u64 len_envp = push_uarg_array(src_pt, argpt, (char **)envp, &td->td_trapframe.sp, argvbuf + len_argv, NULL);

	u64 total_len = len_argv + len_envp;
	argc = len_argv - 1;

	return (stack_arg_t){argvbuf, total_len, argc};
}

void proc_create(const char *name, const void *bin, size_t size) 
{
	proc_t *p = proc_alloc();
	thread_t *inittd = td_alloc();
	proc_addtd(p, inittd);
	proc_uvminit(p, inittd, name, bin, size);
	init_thread_fs(&p->p_fs_struct);
	inittd->td_status = RUNNABLE;
	extern threadq_t thread_runq;
	tdq_critical_enter(&thread_runq);
	TAILQ_INSERT_TAIL(&thread_runq.tq_head, inittd, td_runq);
	mtx_unlock(&inittd->td_lock);
	proc_unlock(p);
	tdq_critical_exit(&thread_runq);
}

u64_t td_fork(thread_t *td, u64_t childsp, u64_t ptid, u64_t tls, u64_t ctid) 
{
	proc_t *p = td->td_proc;
	thread_t *childtd = td_alloc();
	proc_lock(p);
	proc_addtd(p, childtd);
	proc_unlock(p);
	safestrcpy(childtd->td_name, td->td_name, MAX_PROC_NAME_LEN);
	proc_fork_name_debug(childtd);
	childtd->td_status = RUNNABLE;
	childtd->td_trapframe = td->td_trapframe;
	if(childsp != 0) /* 设置子线程的栈顶 */
    {
		childtd->td_trapframe.sp = childsp;
	}
	childtd->td_trapframe.a0 = 0;
	childtd->td_trapframe.tp = tls;
	if(ptid != 0) 
    {
		copyOut(ptid, (void *)&childtd->td_tid, sizeof(u32));
	}
	childtd->td_ctid = ctid;
	extern threadq_t thread_runq;
	tdq_critical_enter(&thread_runq);
	TAILQ_INSERT_TAIL(&thread_runq.tq_head, childtd, td_runq);
	mtx_unlock(&childtd->td_lock);
	tdq_critical_exit(&thread_runq);
	return childtd->td_tid;
}

/*
    功能：基于传入的线程 fork 出一个新的进程，并加入调度队列
*/
u64_t proc_fork(thread_t *td, u64_t childsp, u64_t flags) 
{
	proc_t *p = td->td_proc;
	proc_t *childp = proc_alloc();
	thread_t *childtd = td_alloc();
	proc_lock(p);
	proc_addtd(childp, childtd);

	// 父进程操作
	// 使用写时复制映射父进程的用户线程地址空间
	pdWalk(p->p_pt, duppage, NULL, childp->p_pt); /*  */
	childp->p_brk = p->p_brk;
	safestrcpy(childtd->td_name, td->td_name, MAX_PROC_NAME_LEN);
	proc_fork_name_debug(childtd);
	fork_thread_fs(&p->p_fs_struct, &childp->p_fs_struct);

	if (flags & CLONE_SIGHAND) {
		sigaction_clone(p, childp);
	}

	// 父线程的内核线程信息不用复制，使用新内核线程的入口直接调度
	childtd->td_status = RUNNABLE;

	// 创建进程的父子关系
	childp->p_parent = p;
	LIST_INSERT_HEAD(&p->p_children, childp, p_sibling);
	proc_unlock(p);

	// 复制父线程的用户现场
	childtd->td_trapframe = td->td_trapframe;
	// 设置子线程的栈顶
	if (childsp != 0) {
		childtd->td_trapframe.sp = childsp;
	}
	// 设置子线程的返回值
	childtd->td_trapframe.a0 = 0;

	// 将子进程的初始线程加入调度队列
	extern threadq_t thread_runq;
	tdq_critical_enter(&thread_runq);
	TAILQ_INSERT_TAIL(&thread_runq.tq_head, childtd, td_runq);
	mtx_unlock(&childtd->td_lock);
	proc_unlock(childp);
	tdq_critical_exit(&thread_runq);

	return childp->p_pid;
}

void proc_destroy(proc_t *p, err_t exitcode) 
{
    extern mutex_t wait_lock;
	assert(mtx_hold(&wait_lock));
	p->p_exitcode = exitcode;
