/*
	功能：内核态中断异常处理函数
*/
void kerneltrap(ktrapframe_t *tf) 
{
	// 获取陷入中断的原因
	u64_t scause = r_scause();
	u64_t type = (scause >> 63UL);
	u64_t excCode = (scause & ((1UL << 63) - 1));

	if(type == SCAUSE_INTERRUPT) /* 中断 */
	{
		if(excCode == INTERRUPT_TIMER) /* 时钟中断 */
		{
			ktrap_timer();
		} 
		else if(excCode == INTERRUPT_EXTERNEL) /* 外设中断 */
		{
			trap_device();
		} 
		else 
		{
			log(DEFAULT, "unknown interrupt!\n");
		}
	} 
	else /* 暂不实现异常处理 */
	{
		printf("sp = 0x%016lx, ra = 0x%016lx\n", tf->sp, tf->ra);
		panic("uncaught exception.\n"
		      "\tcpu: %d\n"
		      "\tExcCode: %d\n"
		      "\tCause: %s\n"
		      "\tSepc: 0x%016lx (kern/kernel.asm)\n"
		      "\tStval(bad memory address): 0x%016lx\n",
		      cpu_this_id(), excCode, excCause[excCode], r_sepc(), r_stval());
	}
}

