err_t cow_handler(pte_t *pd, pte_t pte, u64_t badva) 
{
	u64_t newpa = vmAlloc();
	u64_t oldpa = pteToPa(pte);
	memcpy((void *)newpa, (void *)oldpa, PAGE_SIZE);
	u64_t newperm = (PTE_PERM(pte) & ~PTE_COW) | PTE_W;
	return ptMap(pd, badva, newpa, newperm);
}

err_t passive_handler(pte_t *pd, pte_t pte, u64_t badva) 
{
	assert((pte & PTE_PPNMASK) == 0);
	u64_t newpa = vmAlloc();
	u64_t perm = pte;
	warn("passive page fault: badva=%lx, pte=%lx, perm=%lx\n", badva, pte, perm);
	return ptMap(pd, badva, newpa, perm);
}

err_t page_fault_handler(pte_t *pd, u64_t violate, u64_t badva) 
{
	// 查找页表项
	pte_t pte = ptLookup(pd, badva);

	if((violate & PTE_W) && (pte != 0) && (pte & PTE_U) && !(pte & PTE_W) && (pte & PTE_COW)) /* 写时复制：写错误且用户位、只读位、写时复制位 */
	{
		return cow_handler(pd, pte, badva); /*  */
	} 
	else if(!(pte & PTE_V) && (pte & PTE_U)) /* 被动调页 */
	{
		return passive_handler(pd, pte, badva);
	} 
	else 
	{
		asm volatile("nop");
		return -1;
	}
}

void trap_pgfault(thread_t *td, u64_t exc_code) 
{
	u64_t badva = r_stval() & ~(PAGE_SIZE - 1);
	u64_t violation;
	switch(exc_code) 
	{
		case EXCCODE_STORE_PAGE_FAULT:
			violation = PTE_W;
			break;
		case EXCCODE_LOAD_PAGE_FAULT:
			violation = PTE_R;
			break;
		default:
			panic("trap_pgfault: unsupported exc_code");
	}

	if(page_fault_handler(td->td_proc->p_pt, violation, badva)) 
	{
		// 页错误处理失败，发送 SIGSEGV 信号
		pte_t pte = ptLookup(td->td_proc->p_pt, badva);
		char prot[] = "     ";
		if(pte & PTE_U)
		{
			prot[0] = 'U';
		}
		if(pte & PTE_R)
		{
			prot[1] = 'R';
		}
		if(pte & PTE_W)
		{
			prot[2] = 'W';
		}
		if(pte & PTE_X)
		{
			prot[3] = 'X';
		}
		if(pte & PTE_COW)
		{
			prot[4] = 'C';
		}
		warn("page fault caused 'SIGSEGV' on thread %d[%s] prot = %s\n", td->td_tid, td->td_name, prot);
		sig_send_proc(td->td_proc, SIGSEGV);
	}
}

