extern char *sys_names[];

/*
    功能：系统调用入口
*/
void syscall_entry(trapframe_t *tf) 
{
	u64_t sysno = tf->a7;
	syscall_function_t *sys_func = &sys_table[sysno];
    thread_t *td = cpu_this()->cpu_running;

	if(sys_func != NULL && sys_func->name != NULL) 
    {
		if(sysno != SYS_brk 
        && sysno != SYS_read 
        && sysno != SYS_write 
        && sysno != SYS_lseek 
        && sysno != SYS_readv 
        && sysno != SYS_writev 
        && sysno != SYS_pread64 
        && sysno != SYS_pwrite64)
        {
            log(LEVEL_GLOBAL, "Hart %d Thread %s called '%s', epc = %lx\n", cpu_this_id(),
		    	td->td_name, sys_func->name, tf->epc);
        }
        if(sysno != SYS_brk 
        && sysno != SYS_read 
        && sysno != SYS_write 
        && sysno != SYS_lseek 
        && sysno != SYS_readv 
        && sysno != SYS_writev 
        && sysno != SYS_pread64 
        && sysno != SYS_pwrite64)
        {
            log(LEVEL_GLOBAL, "Thread %08x(p %08x) called '%s' start\n", td->td_tid, td->td_proc->p_pid, sys_func->name);
        }
	}

	u64_t (*func)(u64_t, u64_t, u64_t, u64_t, u64_t, u64_t);
	tf->epc += 4;
	func = (u64_t(*)(u64_t, u64_t, u64_t, u64_t, u64_t, u64_t))sys_table[sysno].func; /* 获取系统调用函数 */
	if(func == NULL) 
    {
		tf->a0 = -1;
        if(sysno != SYS_exit_group && sysno != SYS_umask) 
        {
		    printf(FARM_WARN"Unimplemented syscall: %s(%d)"SGR_RESET"\n", sys_names[sysno], sysno);
        }
        return;
	}
	char syscall_name[64] = "sys_";
	strcat(syscall_name, sys_names[sysno]);

	PROFILING_START
	tf->a0 = func(tf->a0, tf->a1, tf->a2, tf->a3, tf->a4, tf->a5);
	PROFILING_END_WITH_NAME(syscall_name)

	if((i64)tf->a0 < 0) 
    {
		warn("ERROR: syscall %s(%d) returned %d\n", sys_names[sysno], sysno, tf->a0);
	}
    if(sysno != SYS_brk 
    && sysno != SYS_read 
    && sysno != SYS_write 
    && sysno != SYS_lseek 
    && sysno != SYS_readv 
    && sysno != SYS_writev 
    && sysno != SYS_pread64 
    && sysno != SYS_pwrite64)
    {
        log(LEVEL_GLOBAL, "Thread %s %08x called '%s' return 0x%lx\n", cpu_this()->cpu_running->td_name, cpu_this()->cpu_running->td_tid, sys_func->name, tf->a0);
    }
}

