 */
int fdAlloc() {
	mtx_lock(&mtx_fd);

	uint i;
	for (i = 0; i < FDNUM; i++) {
		int index = i >> 5;
		int inner = i & 31;
		if ((fdBitMap[index] & (1 << inner)) == 0) {
			fdBitMap[index] |= 1 << inner;

			memset(&fds[i], 0, sizeof(struct Fd));
			fds[i].refcnt = 1;
			mtx_init(&fds[i].lock, "fd_lock", 1, MTX_SLEEP | MTX_RECURSE);

			mtx_unlock(&mtx_fd);
			return i;
		}
	}

	mtx_unlock(&mtx_fd);
