// 局部函数定义
static void sig_beforestart(thread_t *td, sigevent_t *se, sigaction_t *sa);
static void sig_afterret(thread_t *td, sigevent_t *se, sigaction_t *sa);
static bool sig_cancheck(thread_t *td);


/*
	功能：获取当前最高优先级能处理的信号
*/
sigevent_t *sig_getse(thread_t *td) 
{
	assert(mtx_hold(&td->td_lock));
	sigevent_t *se = NULL;
	TAILQ_FOREACH(se, &td->td_sigqueue, se_link) 
	{
		// 若信号正在处理或者信号没被阻塞，返回信号
		if((se->se_status & SE_PROCESSING) || sig_td_canhandle(td, se->se_signo)) 
		{
			return se;
		}
	}
	// 没有信号需要处理
	return NULL;
}

void sig_check() 
{
	thread_t *td = cpu_this()->cpu_running;
	mtx_lock(&td->td_lock);
	while(sig_cancheck(td)) 
	{
		sigevent_t *se = sig_getse(td); /* 获取一个能够处理的信号 */

		if(se == NULL || se->se_status & SE_PROCESSING) /* 没有信号需要处理、或者信号正在处理 */
		{
			break;
		}
		sigaction_t *sa = sigaction_get(td->td_proc, se->se_signo); /* 获取信号处理函数 */
		if(sa->sa_handler == NULL || sa->sa_handler == SIG_IGN) /* 判断信号处理函数是否存在 */
		{
			if(se->se_signo == SIGKILL || se->se_signo == SIGTERM || se->se_signo == SIGSEGV) /* 未注册的信号处理函数 */
			{
				// 默认处理函数：终止进程
				warn("%s handling SIGKILL signal\n", td->td_name);
				td->td_killed = 1;
				continue;
			}
			warn("%s's signal %d ignored\n", td->td_name, se->se_signo);
			sigeventq_remove(td, se);
			sigevent_free(se);
		} 
		else 
		{
			// 已注册的信号处理函数
			warn("%s handling signal %d, handler = %x\n", td->td_name, se->se_signo, sa->sa_handler);
			sig_beforestart(td, se, sa);
			break;
		}
	}
	mtx_unlock(&td->td_lock);
}

void sig_return(thread_t *td) 
{
	sigevent_t *se = NULL;
	mtx_lock(&td->td_lock);
	TAILQ_FOREACH(se, &td->td_sigqueue, se_link) 
	{
		if(se->se_status & SE_PROCESSING) 
		{
			break;
		}
	}
	sig_afterret(td, se, sigaction_get(td->td_proc, se->se_signo));
	sigeventq_remove(td, se);
	sigevent_free(se);
	mtx_unlock(&td->td_lock);
}

void siginfo_set(thread_t *td, sigevent_t *se) 
{
	td->td_trapframe.sp = (td->td_trapframe.sp - sizeof(siginfo_t)) & (~0xf);
	td->td_trapframe.a1 = td->td_trapframe.sp;
	td->td_trapframe.sp = (td->td_trapframe.sp - sizeof(ucontext_t)) & (~0xf);
	td->td_trapframe.a2 = td->td_trapframe.sp;

	siginfo_t siginfo = {0}; /* 初始化 */
	siginfo.si_signo = se->se_signo;

	ucontext_t uctx = {0};
	memcpy(&uctx.uc_sigmask, &td->td_sigmask, sizeof(sigset_t));
	uctx.uc_mcontext.MC_PC = se->se_restoretf.epc;

	se->se_usiginfo = td->td_trapframe.a1; /* 拷贝到用户空间 */
	se->se_uuctx = td->td_trapframe.a2;
	copy_out(td->td_proc->p_pt, se->se_usiginfo, &siginfo, sizeof(siginfo_t));
	copy_out(td->td_proc->p_pt, se->se_uuctx, &uctx, sizeof(ucontext_t));
}

void siginfo_return(thread_t *td, sigevent_t *se) 
{
	ucontext_t uctx_ret;
	copy_in(td->td_proc->p_pt, se->se_uuctx, &uctx_ret, sizeof(ucontext_t));
	if(uctx_ret.uc_mcontext.MC_PC != 0) 
	{
		se->se_restoretf.epc = uctx_ret.uc_mcontext.MC_PC;
	}
	memcpy(&td->td_sigmask, &uctx_ret.uc_sigmask, sizeof(sigset_t));
}

