		TAILQ_INSERT_HEAD(&sigevent_freeq, &sigevents[i], se_link);
	}
	memset(sigactions, 0, sizeof(sigaction_t) * SIGNAL_MAX * NPROC);
}

/*
	功能：信号事件分配
*/
sigevent_t *sigevent_alloc(int signo) 
{
	mtx_lock(&sigevent_lock);
	sigevent_t *se = TAILQ_FIRST(&sigevent_freeq);
	assert(se != NULL);
	TAILQ_REMOVE(&sigevent_freeq, se, se_link);
	mtx_unlock(&sigevent_lock);
	se->se_signo = signo;
	return se;
}

void sigevent_free(sigevent_t *se) 
{
	mtx_lock(&sigevent_lock);
	memset(se, 0, sizeof(sigevent_t));
	TAILQ_INSERT_HEAD(&sigevent_freeq, se, se_link);
	mtx_unlock(&sigevent_lock);
}

void sigevent_freetd(thread_t *td) 
{
	mtx_lock(&sigevent_lock);
	sigevent_t *se;
	while ((se = TAILQ_FIRST(&td->td_sigqueue)) != NULL) {
		sigeventq_remove(td, se);
		sigevent_free(se);
	}
	mtx_unlock(&sigevent_lock);
}

/*
	功能：信号处理函数注册
*/
err_t sigaction_register(int signo, u64_t act, u64_t oldact, int sigset_size) 
{
	assert(0 < signo && signo <= SIGNAL_MAX);
	thread_t *td = cpu_this()->cpu_running;
	extern proc_t procs[];
	sigaction_t *kact = &sigactions[td->td_proc - procs][signo - 1];
	size_t ksa_size = sizeof(sigaction_t) - sizeof(sigset_t) + sigset_size;
	if(oldact != 0) 
	{
		copy_out(td->td_proc->p_pt, oldact, kact, ksa_size);
	}
	if(act != 0) 
	{
		memset(kact, 0, sizeof(sigaction_t));
		copy_in(td->td_proc->p_pt, act, kact, ksa_size);
		if(!(kact->sa_flags & SA_RESTORER)) 
		{
			kact->sa_restorer = 0;
		}
		if(0x1 < (u64_t)kact->sa_handler && (u64_t)kact->sa_handler < 0x10000ul) 
		{
			error("sigaction_register: invalid handler %p", kact->sa_handler);
		}
	}
	return 0;
}

void sigaction_free(proc_t *p) 
{
	extern proc_t procs[];
	memset(&sigactions[p - procs], 0, sizeof(sigactions[0]));
}

void sigaction_clone(proc_t *p, proc_t *childp) 
{
	extern proc_t procs[];
	memcpy(&sigactions[childp - procs], &sigactions[p - procs], sizeof(sigactions[0]));
}

/*
	功能：返回对应的信号处理动作
*/
sigaction_t *sigaction_get(proc_t *p, int signo) 
{
	extern proc_t procs[];
	assert(0 < signo && signo <= SIGNAL_MAX);
	return &sigactions[p - procs][signo - 1];
}

void sigeventq_insert(thread_t *td, sigevent_t *se) 
{
	assert(mtx_hold(&td->td_lock));
	TAILQ_INSERT_HEAD(&td->td_sigqueue, se, se_link);
}

void sigeventq_remove(thread_t *td, sigevent_t *se) 
{
	assert(mtx_hold(&td->td_lock));
	TAILQ_REMOVE(&td->td_sigqueue, se, se_link);
}

bool sig_td_canhandle(thread_t *td, int signo) 
{
	assert(td != NULL);
	mtx_lock(&td->td_lock);
	sigset_t sigset = sigset_or(&td->td_sigmask, &td->td_cursigmask);
	bool canhandle = !sigset_isset(&sigset, signo);
	mtx_unlock(&td->td_lock);
	return canhandle;
}

void sig_send_td(thread_t *td, int signo) 
{
	assert(td != NULL);
	mtx_lock(&td->td_lock);
	sigevent_t *se = sigevent_alloc(signo);
	sigeventq_insert(td, se);
	mtx_unlock(&td->td_lock);

	if(signo == SIGKILL) 
	{
		mtx_lock(&td->td_lock);
		td->td_killed = 1;
		mtx_unlock(&td->td_lock);
		tcleanup(td);
		wakeup_td(td);
	}
}

void sig_send_proc(proc_t *p, int signo) 
{
	assert(p != NULL);
	proc_lock(p);
	if(p->p_status == ZOMBIE) 
	{
		proc_unlock(p);
		warn("sig_send_proc: process %08x is zombie\n", p->p_pid);
		return;
	}
	thread_t *td;
	TAILQ_FOREACH(td, &p->p_threads, td_plist) 
	{
		mtx_lock(&td->td_lock);
		if(sig_td_canhandle(td, signo)) /* 从头部开始找到第一个可以处理该信号的线程 */
		{
			sig_send_td(td, signo);
			mtx_unlock(&td->td_lock);
			proc_unlock(p);
