		}
		mtx_unlock(&td->td_lock);
	}
	if(TAILQ_EMPTY(&p->p_threads)) /* 没有找到可以处理该信号的线程 */
	{
		panic("sig_send_proc: no thread in process %08x\n", p->p_pid);
	}
	td = TAILQ_FIRST(&p->p_threads);
	mtx_lock(&td->td_lock);
	sig_send_td(td, signo);
	mtx_unlock(&td->td_lock);
	proc_unlock(p);
}

