	TAILQ_INIT(&fe_freeq.ftxq_head);
	TAILQ_INIT(&fe_usedq.ftxq_head);

	// 初始化 futex 事件
	for (int i = FUTEXEVENTS_MAX - 1; i >= 0; i--) {
		futexevent_t *fe = &futexevents[i];
		fe->ftx_upaddr = 0;
		fe->ftx_waiterpid = 0;
		TAILQ_INSERT_HEAD(&fe_freeq.ftxq_head, fe, ftx_freeq);
