void virtio_disk_init() 
{
	mtx_init(&mtx_virtio, "virtio", false, MTX_SPIN);

	mtx_lock(&mtx_virtio);
	u32_t status = 0;

	// 检查设备的魔术值、版本、设备ID和厂商ID
	if(*R(VIRTIO_MMIO_MAGIC_VALUE) != 0x74726976 
	|| *R(VIRTIO_MMIO_VERSION) != 1 
	|| *R(VIRTIO_MMIO_DEVICE_ID) != 2 
	|| *R(VIRTIO_MMIO_VENDOR_ID) != 0x554d4551) 
	{
		panic("could not find virtio disk");
	}

	// 将状态寄存器置零，用于重置设备
	*R(VIRTIO_MMIO_STATUS) = status;

	// 设置ACKNOWLEDGE和DRIVER状态位，表示驱动程序已经意识到设备的存在，并准备开始驱动
	status |= VIRTIO_CONFIG_S_ACKNOWLEDGE;
	*R(VIRTIO_MMIO_STATUS) = status;

	status |= VIRTIO_CONFIG_S_DRIVER;
	*R(VIRTIO_MMIO_STATUS) = status;

	// 协商设备和驱动程序所支持的特性，
	u64_t features = *R(VIRTIO_MMIO_DEVICE_FEATURES);
	features &= ~(1 << VIRTIO_BLK_F_RO);
	features &= ~(1 << VIRTIO_BLK_F_SCSI);
	features &= ~(1 << VIRTIO_BLK_F_CONFIG_WCE);
	features &= ~(1 << VIRTIO_BLK_F_MQ);
	features &= ~(1 << VIRTIO_F_ANY_LAYOUT);
	features &= ~(1 << VIRTIO_RING_F_EVENT_IDX);
	features &= ~(1 << VIRTIO_RING_F_INDIRECT_DESC);
	*R(VIRTIO_MMIO_DRIVER_FEATURES) = features;

	// 选择队列0进行初始化
	*R(VIRTIO_MMIO_QUEUE_SEL) = 0;

	// 确保队列0未被使用
	if (*R(VIRTIO_MMIO_QUEUE_PFN) != 0)
	{
		panic("virtio disk should not be ready");
	}

	// 检查最大队列大小
	u32_t max = *R(VIRTIO_MMIO_QUEUE_NUM_MAX);
	if(max == 0)
	{
		panic("virtio disk has no queue 0");
	}
	if(max < NUM)
	{
		panic("virtio disk max queue too short");
	}

	*R(VIRTIO_MMIO_PAGE_SIZE) = PAGE_SIZE;
	disk.desc = (void *)virtio_driver_buf;
	disk.avail = (void *)((u64_t)disk.desc + (sizeof(struct virtq_desc) * NUM));
	disk.used = (void *)((u64_t)disk.desc + PAGE_SIZE);

	if(!disk.desc || !disk.used)
	{
		panic("virtio disk kalloc");
	}
	memset(disk.desc, 0, PAGE_SIZE);
	memset(disk.used, 0, PAGE_SIZE);

