#define mtx_spin_debug(...)                                                                        \
	do {                                                                                       \
		if (m->mtx_debug && (m->mtx_type & MTX_SPIN)) {                                    \
			log(MUTEX_SPIN, __VA_ARGS__);                                              \
		}                                                                                  \
	} while (0)

#define mtx_sleep_debug(...)                                                                       \
	do {                                                                                       \
		if (m->mtx_debug && (m->mtx_type & MTX_SLEEP)) {                                   \
			log(MUTEX_SLEEP, __VA_ARGS__);                                             \
