// 定义pipe设备访问函数
// 内部的函数均应该是可重入函数，即没有static变量，不依赖全局变量（锁除外）
struct FdDev fd_dev_pipe = {
    .dev_id = 'p',
    .dev_name = "pipe",
    .dev_read = fd_pipe_read,
    .dev_write = fd_pipe_write,
    .dev_close = fd_pipe_close,
