{
	intr_off();
	SBI_SYSTEM_RESET(SHUTDOWN, NOREASON);
}

bool cpu_allidle() 
{
	for(int i = 0; i < NCPU; i++) 
	{
		if(!cpus[i].cpu_idle) 
		{
			return false;
		}
	}
	return true;
}

