#include <proc/thread.h>
#include <trap/trap.h>

typedef err_t (*user_kernel_callback_t)(void *uptr, void *kptr, size_t len, void *arg);


extern err_t page_fault_handler(pte_t *pd, u64_t violate, u64_t badva);
static void test_page_fault(Pte *upd, u64_t va, Pte pte, u64_t permneed);
static void userToKernel(Pte *upd, u64_t uptr, void *kptr, size_t len,
			 user_kernel_callback_t callback, u64_t permneed, void *arg);
static int strncpyJudgeEnd(char *s, const char *t, int n);

err_t copyOutCallback(void *uptr, void *kptr, size_t len, void *arg) 
{
	memcpy(uptr, kptr, len);
	return 0;
}

err_t copyInCallback(void *uptr, void *kptr, size_t len, void *arg) {
	memcpy(kptr, uptr, len);
	return 0;
}

err_t copyInStrCallback(void *uptr, void *kptr, size_t len, void *arg) {
	return strncpyJudgeEnd(kptr, uptr, len);
}

/**
 * @brief 将内核的数据拷贝到用户态地址，使用传入的用户态页表
 */
void copyOutOnPageTable(Pte *pgDir, u64_t uPtr, void *kPtr, int len) 
{
	userToKernel(pgDir, uPtr, kPtr, len, copyOutCallback, PTE_W, NULL);
}

/**
 * @brief 将内核的数据拷贝到用户态地址，默认使用当前进程的页表去查询uPtr的物理地址
 */
void copyOut(u64_t uPtr, void *kPtr, int len) 
{
	Pte *pgDir = cur_proc_pt();
	copyOutOnPageTable(pgDir, uPtr, kPtr, len);
}

/**
 * @brief 将用户的数据拷贝入内核
 */
void copyIn(u64_t uPtr, void *kPtr, int len) {
	userToKernel(cur_proc_pt(), uPtr, kPtr, len, copyInCallback, PTE_R, NULL);
}

/**
 * @brief 将用户态的字符串拷贝进内核
 * @param n 表示传输的最大字符数
 */
void copyInStr(u64_t uPtr, void *kPtr, int n) {
	Pte *pgDir = cur_proc_pt();
	userToKernel(pgDir, uPtr, kPtr, n, copyInStrCallback, PTE_R, NULL);
}

void copy_in(Pte *upd, u64_t uptr, void *kptr, size_t len) {
	userToKernel(upd, uptr, kptr, len, copyInCallback, PTE_R, NULL);
}

void copy_in_str(Pte *upd, u64_t uptr, void *kptr, size_t len) {
	userToKernel(upd, uptr, kptr, len, copyInStrCallback, PTE_R, NULL);
}

void copy_out(Pte *upd, u64_t uptr, void *kptr, size_t len) {
	userToKernel(upd, uptr, kptr, len, copyOutCallback, PTE_W, NULL);
}

/**
 * @brief 本文件规定与thread的通用接口，包括init, fork, recycle三个动作时对进程管理的fs结构的处理
 * 本结构体的互斥场景仅仅需要考虑同一进程不同线程的互斥即可
 */

#include <fs/console.h>
#include <fs/fd.h>
#include <fs/file.h>
#include <fs/thread_fs.h>
#include <fs/vfs.h>
#include <lib/error.h>
#include <lib/string.h>
#include <lock/mutex.h>

void init_thread_fs(thread_fs_t *fs_struct) {
	strncpy(fs_struct->cwd, "/", 2);

	// 初始化文件描述符表
	for (int i = 0; i < MAX_FD_COUNT; i++) {
		fs_struct->fdList[i] = -1;
	}

	// 初始化控制台文件描述符
	fs_struct->fdList[0] = readConsoleAlloc();
	fs_struct->fdList[1] = writeConsoleAlloc();
	fs_struct->fdList[2] = errorConsoleAlloc();

	fs_struct->cwd_dirent = NULL;

	// 初始化MMAP区域的开始位置
	fs_struct->mmap_addr = MMAP_START;

	fs_struct->rlimit_files_cur = MAX_FD_COUNT;
	fs_struct->rlimit_files_max = MAX_FD_COUNT;

	// 初始化进程fs结构体的锁为自旋锁
	mtx_init(&fs_struct->lock, "thread_fs_lock", true, MTX_SPIN);
}

// 不设置cwd_dirent是为了在get_cwd_dirent时设置
void fork_thread_fs(thread_fs_t *old, thread_fs_t *new) {
	strncpy(new->cwd, old->cwd, MAX_NAME_LEN);

	// 复制父进程已打开的文件
	for (int i = 0; i < MAX_FD_COUNT; i++) {
		int kFd = old->fdList[i];
		if (kFd != -1) {
			cloneAddCite(kFd);
		}
		new->fdList[i] = kFd;
	}

	// fork时子进程继承父进程的MMAP
	new->mmap_addr = old->mmap_addr;

	// 继承文件数的限制
	new->rlimit_files_cur = old->rlimit_files_cur;
	new->rlimit_files_max = old->rlimit_files_max;

	// 初始化进程fs结构体的锁为自旋锁
	mtx_init(&new->lock, "thread_fs_lock", true, MTX_SPIN);
}

void recycle_thread_fs(thread_fs_t *fs_struct) {
	fs_struct->cwd[0] = 0;

	// 回收进程的文件描述符
	for (int i = 0; i < MAX_FD_COUNT; i++) {
		if (fs_struct->fdList[i] != -1) {
			freeFd(fs_struct->fdList[i]);
		}
	}

	if (fs_struct->cwd_dirent != NULL) {
		file_close(fs_struct->cwd_dirent);
	}
}

